def eat_taco(num_tacos,tip):
    num_tacos -= 1
    if taco = good:
        tip += 0.5
    return num_tacos, tip 

def taco_truck_tip_calc(tacos):
    tip = 0
    while tacos &gt; 0:
        tacos, tip = eat_taco(tacos, tip)
    return tip


print(taco_truck_tip_calc(5))

